import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';
import './Wishlist.css';
import { IoSearch } from 'react-icons/io5';
import { FaHotel, FaMapMarkedAlt, FaHome, FaTree, FaStar } from 'react-icons/fa';

const Wishlist = () => {
  const { user, updateUser } = useAuth();
  const navigate = useNavigate();

  const [wishlist, setWishlist] = useState([]);
  const [loading, setLoading] = useState(true);
  const [removing, setRemoving] = useState(null);
  const [filter, setFilter] = useState('All');
  const [sortBy, setSortBy] = useState('recent');

  // ✅ FIXED: simple single fetch (NO useCallback, NO loop)
  useEffect(() => {
    const fetchWishlist = async () => {
      setLoading(true);

      try {
        const { data } = await authAPI.getMe();
        const items = data.user?.wishlist || [];

        const populated = items.filter(
          item => typeof item === 'object' && item !== null && item.title
        );

        setWishlist(populated);

        // ⚠️ optional: update user safely (prevents unnecessary rerender loops)
        if (updateUser && JSON.stringify(user) !== JSON.stringify(data.user)) {
          updateUser(data.user);
        }

      } catch (err) {
        toast.error('Failed to load wishlist');
      } finally {
        setLoading(false);
      }
    };

    fetchWishlist();
  }, []); // ✅ IMPORTANT: run only once

  // Remove item from wishlist
  const handleRemove = async (propertyId, e) => {
    e.preventDefault();
    e.stopPropagation();

    setRemoving(propertyId);

    try {
      await authAPI.toggleWishlist(propertyId);
      setWishlist(prev => prev.filter(p => p._id !== propertyId));
      toast.success('Removed from wishlist');
    } catch {
      toast.error('Failed to remove');
    } finally {
      setRemoving(null);
    }
  };

  // Filter & sort
  const filtered = wishlist
    .filter(p => filter === 'All' || p.location?.region === filter)
    .sort((a, b) => {
      if (sortBy === 'price_asc') return a.price - b.price;
      if (sortBy === 'price_desc') return b.price - a.price;
      if (sortBy === 'rating') return b.rating - a.rating;
      return 0;
    });

  const usedRegions = [...new Set(
    wishlist.map(p => p.location?.region).filter(Boolean)
  )];

  const typeIcons = {
    hotel: '🏨',
    guesthouse: '🏡',
    cabin: '🪵',
    resort: '✨',
    hostel: '🛏',
    apartment: '🏢',
  };

  if (loading) {
    return (
      <div className="wishlist-page">
        <div className="wl-hero">
          <div className="container wl-hero-content">
            <h1>❤️ My Wishlist</h1>
            <p>Loading your saved properties...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="wishlist-page">

      {/* Hero */}
      <div className="wl-hero">
        <div className="container wl-hero-content">
          <div>
            <h1>❤️ My Wishlist</h1>
            <p>
              {wishlist.length === 0
                ? 'Start saving properties you love'
                : `${wishlist.length} saved properties`}
            </p>
          </div>

          <Link to="/stays" className="btn btn-primary">
            <IoSearch style={{ width: 20, height: 20 }} /> Explore More
          </Link>
        </div>
      </div>

      <div className="container">

        {/* Empty State */}
        {wishlist.length === 0 && (
          <div className="wl-empty">
            <div className="wl-empty-icon">🤍</div>
            <h2>Your wishlist is empty</h2>
            <p>Browse stays and save your favorites.</p>

            <Link to="/stays" className="btn btn-primary">
              <FaHotel style={{ marginRight: 8 }} /> Browse Stays
            </Link>
          </div>
        )}

        {/* Grid */}
        {filtered.length > 0 && (
          <div className="wl-grid">
            {filtered.map(property => {
              const mainImage =
                property.images?.[0]?.url ||
                'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600';

              const isRemoving = removing === property._id;

              return (
                <div
                  key={property._id}
                  className={`wl-card ${isRemoving ? 'removing' : ''}`}
                  onClick={() => navigate(`/stays/${property._id}`)}
                >
                  <div className="wl-card-img">
                    <img src={mainImage} alt={property.title} />

                    <button
                      className="wl-heart-btn"
                      onClick={(e) => handleRemove(property._id, e)}
                    >
                      {isRemoving ? '⏳' : '❤️'}
                    </button>

                    <span className="wl-type-badge">
                      {typeIcons[property.propertyType] || '🏠'} {property.propertyType}
                    </span>
                  </div>

                  <div className="wl-card-body">
                    <h3>{property.title}</h3>

                    <div className="wl-price">
                      PKR {property.price?.toLocaleString()} / night
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

      </div>
    </div>
  );
};

export default Wishlist;
